// // This module implements a 4-input NOR gate with one of the inputs inverted. The output Y is HIGH only when all inputs A, B, C are LOW and D_N is LOW.
module top_module(
    Y  ,
    A  ,
    B  ,
    C  ,
    D_N
);// Module ports
    output Y  ;
    input  A  ;
    input  B  ;
    input  C  ;
    input  D_N;

    // Module supplies
    supply1 VPWR;
    supply0 VGND;
    supply1 VPB ;
    supply0 VNB ;

    // Local signals
    wire not0_out  ;
    wire nor0_out_Y;

    //  Name  Output      Other arguments
    not not0 (not0_out  , D_N              );
    nor nor0 (nor0_out_Y, A, B, C, not0_out);
    buf buf0 (Y         , nor0_out_Y       );

endmodule
